const body = $input.first().json.body || {};

// Only handle push events (ignore pings, PRs, etc.)
const eventType = $input.first().json.headers?.['x-github-event'] || '';
if (eventType === 'ping') {
  return [{ json: { route: 'ping' } }];
}
if (eventType !== 'push' && eventType !== '') {
  return [{ json: { route: 'ignore' } }];
}

const repo = body.repository?.name || 'unknown';
const repoFullName = body.repository?.full_name || repo;
const branch = (body.ref || '').replace('refs/heads/', '');
const pusher = body.pusher?.name || body.sender?.login || 'unknown';
const compareUrl = body.compare || '';
const commits = body.commits || [];

// Skip branch deletes
if (body.deleted) {
  return [{ json: { route: 'ignore' } }];
}

// Format commit list (max 5)
const MAX_COMMITS = 5;
const commitLines = commits.slice(0, MAX_COMMITS).map(c => {
  const msg = (c.message || '').split('\n')[0].slice(0, 72);
  const sha = (c.id || '').slice(0, 7);
  const author = c.author?.name || pusher;
  return `  \`${sha}\` ${msg} — _${author}_`;
});

if (commits.length > MAX_COMMITS) {
  commitLines.push(`  _...and ${commits.length - MAX_COMMITS} more_`);
}

// Files changed summary
const allFiles = commits.flatMap(c => [
  ...(c.added || []),
  ...(c.modified || []),
  ...(c.removed || [])
]);
const uniqueFiles = [...new Set(allFiles)];
const filesSummary = uniqueFiles.length <= 4
  ? uniqueFiles.map(f => `\`${f}\``).join(', ')
  : `${uniqueFiles.slice(0,3).map(f => `\`${f}\``).join(', ')} +${uniqueFiles.length - 3} more`;

const commitWord = commits.length === 1 ? 'commit' : 'commits';

const message = [
  `:github: *Push to \`${repoFullName}\`* — branch \`${branch}\``,
  `*${commits.length} ${commitWord}* by *${pusher}*${compareUrl ? ` | <${compareUrl}|view diff>` : ''}`,
  ``,
  commitLines.join('\n'),
  uniqueFiles.length > 0 ? `\n*Files:* ${filesSummary}` : ''
].filter(Boolean).join('\n');

return [{ json: { route: 'push', message } }];
